/// <summary>
/// Controller class for ZeroRatedSalesReport report
/// </summary>
internal final class ETGZeroRatedSalesReportController extends SrsReportRunController
{
}

Method.Source:
public static ETGZeroRatedSalesReportController construct()
{
    return new ETGZeroRatedSalesReportController();

}

/// <summary>
/// Class entry point. The system will call this method when a designated menu
/// is selected or when execution starts and this class is set as the startup class.
/// </summary>
/// <param name = "_args">The specified arguments.</param>
public static void main(Args _args)
{
    ETGZeroRatedSalesReportController controller =  ETGZeroRatedSalesReportController::construct();

    controller.parmReportName(ssrsReportStr(ETGZeroRatedSalesReport, Report));
    controller.parmArgs(_args);
    controller.parmLoadFromSysLastValue(false);
    controller.startOperation();
}
